def validate_5_step_structure(script_sections: list) -> dict: """Validate 5-step structure is complete.""" required_steps = ["hook", "results", "opportunity", "offer", "cta"]
present = [s.get("name", "").lower() for s in script_sections] missing = [step for step in required_steps if step not in present]
return { "passed": len(missing) == 0, "steps_present": len(present), "missing_steps": missing, "recommendation": f"Add missing sections: {', '.join(missing)}" if missing else None }


def validate_proof_front_loaded(script_sections: list) -> dict:
    """Check proof is front-loaded in Results section."""
    results_section = None
    for section in script_sections:
        if section.get("name", "").lower() in ["results", "front-load results"]:
            results_section = section
            break

    if not results_section:
        return {
            "passed": False,
            "issue": "No Results section found",
            "recommendation": "Add front-loaded proof section (Step 2)"
        }

    proof_count = results_section.get("proof_count", 0)

    return {
        "passed": proof_count >= 2,
        "proof_count": proof_count,
        "target": "2-3 proof hits minimum",
        "recommendation": "Add more proof hits" if proof_count < 2 else None
    }

def check_time_discipline(script_sections: list, target_minutes: int) -> dict: """Check script stays within length target.""" total_seconds = sum(s.get("duration_seconds", 0) for s in script_sections) total_minutes = total_seconds / 60
target_seconds = target_minutes * 60 over_by = total_seconds - target_seconds
return { "passed": over_by <= 30, # 30 second grace "total_minutes": round(total_minutes, 1), "target_minutes": target_minutes, "over_by_seconds": max(0, over_by), "recommendation": f"Cut {int(over_by)} seconds" if over_by > 30 else None }


def validate_single_cta(cta_section: dict) -> dict:
    """Check for single dominant CTA."""
    cta_actions = cta_section.get("cta_actions", [])

    issues = []
    if len(cta_actions) == 0:
        issues.append("No CTA action found")
    elif len(cta_actions) > 1:
        issues.append(f"Multiple CTAs detected: {cta_actions}. Should be single dominant action.")

    return {
        "passed": len(issues) == 0,
        "cta_count": len(cta_actions),
        "issues": issues,
        "recommendation": "Consolidate to single dominant CTA"
    }
